defmodule SessionController do
  @moduledoc false

  def login(conn, %{"username" => username, "password" => password}) do
    if authenticate(username, password) do
      conn
      |> SessionManager.put_session(:user_id, generate_user_id(username))
      |> SessionManager.put_session(:username, username)
      |> SessionManager.put_session(:logged_in_at, DateTime.utc_now())
      |> send_response(200, %{status: "logged_in", username: username})
    else
      send_response(conn, 401, %{error: "invalid_credentials"})
    end
  end

  def logout(conn, _params) do
    conn
    |> SessionManager.clear_session()
    |> send_response(200, %{status: "logged_out"})
  end

  def current_user(conn, _params) do
    case SessionManager.get_session(conn, :user_id) do
      nil ->
        send_response(conn, 401, %{error: "not_authenticated"})
      
      user_id ->
        username = SessionManager.get_session(conn, :username)
        logged_in_at = SessionManager.get_session(conn, :logged_in_at)
        
        send_response(conn, 200, %{
          user_id: user_id,
          username: username,
          logged_in_at: logged_in_at
        })
    end
  end

  def update_session(conn, %{"key" => key, "value" => value}) do
    conn
    |> SessionManager.put_session(String.to_atom(key), value)
    |> send_response(200, %{status: "updated", key: key, value: value})
  end

  defp authenticate(username, password) do
    username == "admin" && password == "password"
  end

  defp generate_user_id(username) do
    :crypto.hash(:md5, "#{username}#{:os.system_time()}") |> Base.encode16()
  end

  defp send_response(conn, status, body) do
    conn
    |> Plug.Conn.put_resp_content_type("application/json")
    |> Plug.Conn.send_resp(status, Jason.encode!(body))
  end
end

